/* ── Helpers ── */
function n(v, fallback = 0) { const x = Number(v); return isFinite(x) ? x : fallback }

function driftColor(drift) {
  if (drift == null) return T.textSecondary
  if (drift < 5) return T.green
  if (drift < 15) return T.amber
  return T.red
}
function driftBg(drift) {
  if (drift == null) return 'transparent'
  if (drift < 5) return 'rgba(34, 197, 94, 0.10)'
  if (drift < 15) return 'rgba(245, 158, 11, 0.10)'
  return 'rgba(239, 68, 68, 0.10)'
}
function driftLabel(drift) {
  if (drift == null) return '--'
  if (drift < 5) return 'Aligned'
  if (drift < 15) return 'Minor'
  return 'Significant'
}
function returnColor(val) {
  if (val > 0) return T.green
  if (val < 0) return T.red
  return T.textSecondary
}
function returnBg(val) {
  if (val > 3) return 'rgba(34, 197, 94, 0.18)'
  if (val > 1) return 'rgba(34, 197, 94, 0.10)'
  if (val > 0) return 'rgba(34, 197, 94, 0.05)'
  if (val > -1) return 'rgba(239, 68, 68, 0.05)'
  if (val > -3) return 'rgba(239, 68, 68, 0.10)'
  return 'rgba(239, 68, 68, 0.18)'
}
function formatDate(isoStr) {
  try { return new Date(isoStr).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }) }
  catch { return isoStr }
}
function formatDateShort(isoStr) {
  try { return new Date(isoStr).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) }
  catch { return isoStr }
}
function daysSince(isoStr) {
  try { return Math.floor((new Date() - new Date(isoStr)) / 86400000) }
  catch { return '---' }
}

/* ── Sort icon ── */
function SortIcon({ active, dir }) {
  if (!active) return <span style={{ opacity: 0.3, marginLeft: 4, fontSize: 10 }}>{'\u2195'}</span>
  return <span style={{ marginLeft: 4, fontSize: 10, color: T.blue }}>{dir === 'asc' ? '\u2191' : '\u2193'}</span>
}

